/**
 * @fileoverview Shared SVG icon strings — deduplicated icons used by 2+ components.
 *
 * Each icon is generated via the centralised Icons API (`Icons.svg()`),
 * ensuring consistent stroke style and easy maintenance.
 *
 * @module shared/tokens/icons
 */

import Icons from '../../Icons.js';

// ── Navigation chevrons (14×14) ─────────────
// Used by: CalendarView, DatePicker

/** Chevron-left / previous arrow. */
export const ICON_CHEVRON_PREV = Icons.svg('chevron-left', { size: 14, strokeWidth: 1.5 });

/** Chevron-right / next arrow. */
export const ICON_CHEVRON_NEXT = Icons.svg('chevron-right', { size: 14, strokeWidth: 1.5 });

// ── Close / dismiss (×) icons ───────────────
// Multiple sizes exist; each component picks the appropriate variant.

/** Close icon — 16×16 (Dialog). */
export const ICON_CLOSE_16_24 = Icons.svg('xmark', { size: 16, strokeWidth: 2 });

/** Close icon — 16×16 (ClipBox darkroom). */
export const ICON_CLOSE_16_16 = Icons.svg('xmark', { size: 16, strokeWidth: 1.8 });

/** Close icon — 14×14 (CalendarView popup). */
export const ICON_CLOSE_14 = Icons.svg('xmark', { size: 14, strokeWidth: 1.8 });

/** Close / delete icon — 12×12 (TreeView delete). */
export const ICON_CLOSE_12 = Icons.svg('xmark', { size: 12, strokeWidth: 2 });

// ── SVG namespace ───────────────────────────
/** SVG XML namespace URI. */
export const SVG_NS = 'http://www.w3.org/2000/svg';
